export type CircuitBreakerState = "closed" | "open" | "half-open";

export interface CircuitBreakerOptions {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests?: number;
  failureStatusCodes?: number[];
}

export interface ResolvedCircuitBreakerOptions {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: number[];
}

export const DEFAULT_CIRCUIT_BREAKER_OPTIONS: ResolvedCircuitBreakerOptions = {
  threshold: 5,
  cooldown: 30_000,
  halfOpenMaxRequests: 1,
  failureStatusCodes: [408, 409, 425, 429, 500, 502, 503, 504],
};

interface CircuitRecord {
  state: CircuitBreakerState;
  failures: number;
  openedAt: number;
  halfOpenInFlight: number;
}

export type CircuitBreakerRegistry = Map<string, CircuitRecord>;

// Attached to the registry via this symbol so `{...globalOptions}` (used by
// `$fetch.create`) carries the same Map reference to derived clients.
const REGISTRY_KEY = Symbol.for("ofetch.circuitBreakerRegistry");

export function getCircuitBreakerRegistry(
  globalOptions: Record<PropertyKey, any>
): CircuitBreakerRegistry {
  if (!globalOptions[REGISTRY_KEY]) {
    globalOptions[REGISTRY_KEY] = new Map();
  }
  return globalOptions[REGISTRY_KEY];
}

export function resolveCircuitBreakerOptions(
  option: true | CircuitBreakerOptions
): ResolvedCircuitBreakerOptions {
  if (option === true) {
    return { ...DEFAULT_CIRCUIT_BREAKER_OPTIONS };
  }
  return {
    threshold: option.threshold ?? DEFAULT_CIRCUIT_BREAKER_OPTIONS.threshold,
    cooldown: option.cooldown ?? DEFAULT_CIRCUIT_BREAKER_OPTIONS.cooldown,
    halfOpenMaxRequests:
      option.halfOpenMaxRequests ??
      DEFAULT_CIRCUIT_BREAKER_OPTIONS.halfOpenMaxRequests,
    failureStatusCodes:
      option.failureStatusCodes ??
      DEFAULT_CIRCUIT_BREAKER_OPTIONS.failureStatusCodes,
  };
}

export function resolveCircuitOrigin(request: FetchRequest): string {
  if (typeof request === "string") {
    try {
      return new URL(request).origin;
    } catch {
      return request;
    }
  }
  if (request instanceof URL) {
    return request.origin;
  }
  if (typeof Request !== "undefined" && request instanceof Request) {
    return new URL(request.url).origin;
  }
  return String(request);
}

function getRecord(
  registry: CircuitBreakerRegistry,
  origin: string
): CircuitRecord {
  let record = registry.get(origin);
  if (!record) {
    record = { state: "closed", failures: 0, openedAt: 0, halfOpenInFlight: 0 };
    registry.set(origin, record);
  }
  return record;
}

export type CircuitOutcome = "success" | "failure" | "neutral";

export interface CircuitBreakerContext {
  origin: string;
  options: ResolvedCircuitBreakerOptions;
  isProbe: boolean;
  concluded: boolean;
  registry: CircuitBreakerRegistry;
}

export class CircuitBreakerOpenError extends Error {
  constructor(origin: string, reason: string) {
    super(`Circuit breaker is open for origin "${origin}" (${reason})`);
    this.name = "CircuitBreakerOpenError";
  }
}

/**
 * Runs the fast-fail / half-open-slot check exactly once per logical
 * request. Retries reuse the same `CircuitBreakerContext` instance (carried
 * through via the resolved options object), so this must not be called again
 * once a context has been attached.
 */
export function prepareCircuitBreaker(
  origin: string,
  option: true | CircuitBreakerOptions,
  registry: CircuitBreakerRegistry
): CircuitBreakerContext {
  const options = resolveCircuitBreakerOptions(option);
  const record = getRecord(registry, origin);

  const now = Date.now();
  if (record.state === "open" && now - record.openedAt >= options.cooldown) {
    record.state = "half-open";
    record.halfOpenInFlight = 0;
  }

  if (record.state === "open") {
    throw new CircuitBreakerOpenError(origin, "circuit is open");
  }

  let isProbe = false;
  if (record.state === "half-open") {
    if (record.halfOpenInFlight >= options.halfOpenMaxRequests) {
      throw new CircuitBreakerOpenError(origin, "half-open probe limit reached");
    }
    record.halfOpenInFlight++;
    isProbe = true;
  }

  return { origin, options, isProbe, concluded: false, registry };
}

/**
 * Finalizes the logical request's effect on circuit state. Idempotent per
 * `CircuitBreakerContext` instance so it is safe to call from multiple
 * conclusion points (success return, hook errors, exhausted retries).
 */
export function concludeCircuit(
  cb: CircuitBreakerContext | undefined,
  outcome: CircuitOutcome
): void {
  if (!cb || cb.concluded) {
    return;
  }
  cb.concluded = true;

  const record = getRecord(cb.registry, cb.origin);
  if (cb.isProbe && record.halfOpenInFlight > 0) {
    record.halfOpenInFlight--;
  }

  if (outcome === "success") {
    record.failures = 0;
    record.state = "closed";
  } else if (outcome === "failure") {
    if (record.state === "half-open") {
      record.state = "open";
      record.openedAt = Date.now();
    } else {
      record.failures++;
      if (record.failures >= cb.options.threshold) {
        record.state = "open";
        record.openedAt = Date.now();
      }
    }
  }
  // "neutral" outcome: release the half-open slot (already done above) but
  // leave failure count / state untouched.
}
